package com.restaurant.controller; import com.restaurant.common.ApiResponse; import com.restaurant.dto.coupon.*; import com.restaurant.service.CouponService; import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/coupons") @RequiredArgsConstructor public class CouponController { private final CouponService service; @PostMapping("/validate") public ApiResponse<CouponValidateResponse> validate(@Valid @RequestBody CouponValidateRequest r){return ApiResponse.ok("Coupon checked", service.validate(r));}}
